        $acronyms = [
            ['AAESQ', 'Association of Administrators of English School boards of Quebec', 'AAESQ is a provincial organization representing 475 school/centre and board level administrators across the Province of Quebec working for Anglophone school boards. We also represent over 200 retired administrators.', 'https://www.aaesq.ca/', 'https://qesba.qc.ca/wp-content/uploads/2021/10/AAESQ_500x500-1.png', 'Centres de services scolaires'],
            ['ACCC', 'Association des Collèges Communautaires du Canada', 'À propos de Collèges et instituts Canada Fondée en 1972, notre association est le porte-parole national et international du plus grand réseau d’enseignement postsecondaire du Canada. Nos actions sont dictées par une vision à la fois simple et ambitieuse : bâtir un avenir meilleur pour les individus et les collectivités. Pour ce faire, nous œuvrons à consolider le réseau des collèges, instituts, cégeps et écoles polytechniques publics du Canada. Plus de 95% des Canadiennes et des Canadiens vivent à moins de 50 km d’un établissement membre et nous bénéficions d’une vaste présence dans le monde entier. L’impact de notre réseau est dès lors sans pareil, et les résultats en sont tangibles pour les étudiantes et étudiants, les employeurs et tous nos partenaires. À l’image de nos membres, nous sommes une organisation souple, capable de s’adapter et d’entreprendre de nouveaux projets au gré des besoins, afin de protéger les collectivités au Canada et à l’étranger des aléas du futur.', 'https://www.collegesinstitutes.ca/fr/', 'https://www.collegesinstitutes.ca/wp-content/themes/cicancorp/assets/images/logo-fr.png', 'Associations et organismes professionnels'],
            ['ACCPQ', 'Association des Conseillères et des Conseillers Pédagogiques du Québec', 'Mission L’Association des Conseillères et Conseillers Pédagogiques du Québec soutient le développement professionnel en créant un réseau entre les membres et avec des partenaires. «L’efficacité n’est pas le fruit du hasard» alors, venez rejoindre notre réseau en devenant membre. Notre vision Être une communauté de conseillères et de conseillers pédagogiques issus des institutions scolaires du Québec et réseautés autour d’une identité professionnelle reconnue Notre mission Soutenir le développement professionnel des conseillères et conseillers pédagogiques des institutions scolaires du Québec par la création d’un réseau entre les membres et avec des partenaires Les objectifs Faire la promotion de la formation continue Réseauter les membres Faire rayonner l’expertise Soutenir l’insertion professionnelle Nos valeurs Le professionnalisme L’innovation La collaboration Un sentiment d’appartenance', 'https://accpq.org/', 'https://i0.wp.com/accpq.org/wp-content/uploads/2020/08/cropped-ACCPQ_LOGO_arbre-et-lettre-sans-fond.png', 'Formation générale et diplômes'],
            ['ACDEC', 'Association Canadienne De l\'Enseignement Coopératif', 'Mission Promouvoir et soutenir l’apprentissage pratique, intégré au travail, par le développement des stages, auprès des acteurs des réseaux de l’enseignement supérieur et du marché du travail. Vision Faire partie de la solution à propos des besoins du marché du travail concernant la main-d’oeuvre en formation par la vulgarisation et la diffusion des connaissances touchant à l’apprentissage intégré au travail. Également, pérenniser la structure du Réseau AIT pour le bienfait de ses membres.', 'https://www.acdec-quebec.ca/', 'https://www.acdec-quebec.ca/wp-content/uploads/2023/06/cropped-logo-reseau-ait512png.png', 'Associations et organismes professionnels'],
            ['ACES', 'Administrators of Complementary Services', 'Lien vers le site Internet', 'https://lceeq.ca/en/committee-list/administrators-complementary-educational-services-aces#:~:text=Description%3A,relate%20to%20Complementary%20Educational%20Services.', 'https://lceeq.ca/sites/all/themes/lstrap_v2/logo.png', 'Technologies éducatives et numérique'],
            ['ACFAS', 'L\'Association Canadienne-Française pour l\'Avancement des Sciences', 'L\'Acfas, au service de l\'avancement des savoirs L’Acfas est un organisme à but non lucratif contribuant à l’avancement des sciences au Québec, dans la francophonie canadienne et sur la scène francophone internationale. Depuis mai 2019, l\'Association se dénomme tout simplement Acfas. Fondée en 1923 sous le nom d’Association canadienne-française pour l’avancement des sciences, l’organisme a été renommé Association francophone pour le savoir entre 2001 et mai 2019. Depuis bientôt 100 ans, l\'Acfas fait rayonner les savoirs comme moteur de développement de nos sociétés en rassemblant les actrices et acteurs de la recherche au sein de la francophonie. Résolument tournée vers l\'avenir, elle est un puissant vecteur de démocratisation et de communication scientifique. Elle valorise les chercheuses et chercheurs de toutes les disciplines, ainsi que l\'excellence en recherche.', 'https://www.acfas.ca/', 'https://www.acfas.ca/themes/custom/acfas_bs4/opengraph.png', 'Associations et organismes professionnels'],
            ['ACSQ', 'Association des Cadres Scolaire du Québec', 'L’AQCS rassemble et soutient ses membres. Elle œuvre à l’amélioration des conditions d’emploi et à la défense des droits de ses membres de façon individuelle et collective. Elle veille au développement des compétences professionnelles de ses membres à toutes les étapes de leur carrière. Par ses interventions, elle contribue à l’évolution du réseau public de l’éducation.', 'https://www.aqcs.ca/', 'https://www.aqcs.ca/wp-content/uploads/2024/04/aqcs-image-partage-1.png', 'Associations et organismes professionnels'],
            ['ADGESBQ', 'Association of Directors General of the English School Boards of Quebec', '', '', 'https://recit.qc.ca/wp-content/uploads/2017/08/logo_recit.png', 'Centres de services scolaires'],
            ['ADGSQ', 'Association des directions générales scolaires du Québec', 'L’Association regroupe les directeurs généraux et directeurs généraux adjoints des centres et services scolaires du Québec. L\' ADIGECS devient l\'ADGSQ ! L\'Association des directions générales scolaires du Québec (ADGSQ) regroupe plus de 188 directions générales et directions', 'https://adgsq.ca/', 'https://adgsq.ca/wp-content/themes/basta/images/logo.png', 'Associations et organismes professionnels'],
            ['ADIGECS', 'Association des DIrecteurs GÉnéraux des Commissions Scolaire', 'L’Association regroupe les directeurs généraux et directeurs généraux adjoints des centres et services scolaires du Québec. L\' ADIGECS devient l\'ADGSQ ! L\'Association des directions générales scolaires du Québec (ADGSQ) regroupe plus de 188 directions générales et directions', 'https://adgsq.ca/', 'https://adgsq.ca/wp-content/themes/basta/images/logo.png', 'Ministères et organismes gouvernementaux'],
            ['ADL', 'Agents De Liaison', 'Agents de liaison Les agents de liaison en formation professionnelle (FP) collaborent, à titre de porte-parole des centres de services scolaires, à l’ensemble des étapes du processus de développement et d’actualisation des programmes de formation. Ils réalisent ce mandat en concertation avec les responsables de secteurs du ministère de l’Éducation du Québec (MEQ). Les agents de liaison sont aussi les conseillers privilégiés des représentants des organisations scolaires qui siègent au sous-comité des programmes du Comité national des programmes d’études professionnelles et techniques (CNPEPT). Ils exercent également une fonction de veille sectorielle. Le rôle de la TRÉAQ concerne le recrutement, la coordination et la consultation des agents de liaison. Depuis 1999, la TRÉAQ joue un rôle majeur pour assurer, notamment, que tous les secteurs de formation soient bien représentés. Lien vers le site Internet', 'https://www.treaq.ca/formation-professionnelle/programmes/agents-de-liaison/', 'https://www.treaq.ca/wp-content/themes/treaq/assets/images/logo.svg', 'Ministères et organismes gouvernementaux'],
            ['AEC', 'Attestation d\'études collégiales', '', '', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Formation professionnelle et technique'],
            ['AENS', 'Attestation d’Équivalence de Niveau de Scolarité', 'La réussite du TENS permet d’obtenir une attestation d’équivalence de niveau de scolarité du secondaire (AENS). Cette attestation favorise l’accès à des emplois exigeant le diplôme d’études secondaires (DES) ou l’équivalent aux élèves de 16 ans et plus. L’AENS permet aussi de remplir les conditions d’admission de plusieurs champs de formation professionnelle au secondaire', 'https://www.cssdm.gouv.qc.ca/education-adultes/evaluations/tests-equivalence-niveau-scolarite-tens/', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Formation professionnelle et technique'],
            ['AEP', 'Attestation d’Études Professionnelles', 'D’abord, une AEP c’est quoi? Une AEP c’est une attestation d’études professionnelles qui permet d’acquérir des compétences donnant accès au marché du travail ou encore à la formation professionnelle. L’ attestation d’études professionnelles (AEP) , c’est également un programme d’études de courte durée qui comporte des stages de quelques semaines. D’ailleurs, les AEP sont des programmes développés et mis sur pied par les centres de services scolaire et elles sont habituellement constituées d’une partie du diplôme d’études professionnelles (DEP) afin de permettre de répondre à des besoins bien spécifiques du marché de l’emploi, voire des besoins de mains-d’œuvre. Elles permettent donc d’ intégrer rapidement le marché de l’emploi . L’AEP fait ainsi partie des partenaires du marché du travail. Cependant, il est important d’être au fait que l’AEP n’est pas une finalité en soi. À la suite de ce programme, l’élève détenant les préalables demandés peut également décider de poursuivre ses études et de compléter un diplôme d’études professionnelles (DEP) . À qui s’adresse l’AEP ? Ce type de programme de formation s’adresse à toute personne désirant intégrer le marché de l’emploi rapidement ou encore à ceux qui souhaitent réorienter leur carrière ou retourner aux études.', 'https://macarrieresedessine.com/attestation-etudes-professionnelles-aep/#:~:text=Quels%20sont%20les%20pr%C3%A9alables%20de,langue%20seconde%20et%20en%20math%C3%A9matique.', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Formation professionnelle et technique'],
            ['AESTQ', 'Association de l\'Enseignement de la Science et de la Technologie au Québec', 'Association de l\'Enseignement de la Science et de la Technologie au Québec', '', 'https://cdn.ca.yapla.com/company/CPYT2P3mKNGuh6U60KhaghOE/module/header/aestq-1673031274.png', 'Associations et organismes professionnels'],
            ['AF', 'Autres Fonctions', 'Les grandes nouveautés La tâche est désormais constituée de deux composantes la tâche éducative («TE»), composée des mêmes composantes qu’auparavant, dont les cours et leçons, et les autres tâches professionnelles («ATP»), composées des heures annuelles de ce qu\'on appelait auparavant la tâche complémentaire («TC»), les activités professionnelles («AP») ou les autres fonctions («AF»), selon les ententes locales, ainsi que du le travail personnel («TP»), qu’on appelait auparavant travail de nature personnelle («TNP»).', 'https://www.lafae.qc.ca/comprendre-la-tache-enseignante', 'https://lh3.googleusercontent.com/p/AF1QipPs9sl_bZ2e0gjbp6j9Ipsa11YX8MtN850IJsq5=s680-w680-h510', 'Formation générale et diplômes'],
            ['AFCE', 'Adéquation Formation-Compétences-Emploi', '', 'https://www.emploiquebec.gouv.qc.ca/fileadmin/fichiers/pdf/Publications/00-aluminium-form-emploi.pdf', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Formation professionnelle et technique'],
            ['AFP', 'Attestation de Formation Professionnelle', '', 'https://www.quebec.ca/education/formation-professionnelle-education-adultes/formation-professionnelle', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Formation professionnelle et technique'],
            ['AGA', 'Assemblée Générale Annuelle', '', '', 'https://recit.qc.ca/wp-content/uploads/2017/08/logo_recit.png', 'Gestion et administration scolaire'],
            ['AI', 'Artificial Intelligence', 'Intelligence Artificielle (IA) L\'intelligence artificielle (IA) est un ensemble de théories et de techniques visant à réaliser des machines capables de simuler l\'intelligence humaine. Souvent classée dans le groupe des mathématiques et des sciences cognitives, elle fait appel à la neurobiologie computationnelle (particulièrement aux réseaux neuronaux) et à la logique mathématique (partie des mathématiques et de la philosophie). Elle utilise des méthodes de résolution de problèmes à forte complexité logique ou algorithmique. Par extension, elle comprend, dans le langage courant, les dispositifs imitant ou remplaçant l\'homme dans certaines mises en œuvre de ses fonctions cognitives. Lien vers le site Internet pour la définition Wikipédia', 'https://fr.wikipedia.org/wiki/Intelligence_artificielle', 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/71/Carto_IA_deepLearning.svg/1920px-Carto_IA_deepLearning.svg.png', 'Technologies éducatives et numérique'],
            ['ALDI', 'Advancing Learning in Differentiation and Inclusion', 'Lien vers le site Internet', 'https://blogs.learnquebec.ca/aldi/', 'https://blogs.learnquebec.ca/aldi/files/2012/04/cropped-ALDI_MSWord.jpg', 'Technologies éducatives et numérique'],
            ['ALÉNA', 'Accord de Libre-Échange Nord-Américain', 'Partie I : Dispositions générales Chapitre 1 : Objectifs Article 101 : Établissement de la zone de libre-échange Les Parties au présent accord, en conformité avec l\'article XXIV de l\' Accord général sur les tarifs douaniers et le commerce , établissent par les présentes une zone de libre-échange.', 'https://www.international.gc.ca/trade-commerce/trade-agreements-accords-commerciaux/agr-acc/nafta-alena/fta-ale/01.aspx?lang=fra', 'https://www.international.gc.ca/wcmglobal/frameworks/v4.0.49.1/theme-gcweb-v12.10.0/assets/wmms-blk.svg', 'Technologies éducatives et numérique'],
            ['AP', 'Activités Professionnelles', 'Les grandes nouveautés La tâche est désormais constituée de deux composantes la tâche éducative («TE»), composée des mêmes composantes qu’auparavant, dont les cours et leçons, et les autres tâches professionnelles («ATP»), composées des heures annuelles de ce qu\'on appelait auparavant la tâche complémentaire («TC»), les activités professionnelles («AP») ou les autres fonctions («AF»), selon les ententes locales, ainsi que du le travail personnel («TP»), qu’on appelait auparavant travail de nature personnelle («TNP»).', 'https://www.lafae.qc.ca/comprendre-la-tache-enseignante', 'https://lh3.googleusercontent.com/p/AF1QipPs9sl_bZ2e0gjbp6j9Ipsa11YX8MtN850IJsq5=s680-w680-h510', 'Formation générale et diplômes'],
            ['APEC', 'Association Professionnelle des Enseignant.e.s en Commerce', 'L’Apec a pour objectif de remplir les deux fonctions suivantes : Fonction pédagogique L’Apec vise la participation à l’élaboration : des conditions d’admission des élèves; de l’évaluation et de la révision des programmes d’enseignement; des examens ministériels; du matériel didactique en formation professionnelle. Fonction professionnelle L’Apec vise la représentation de ses membres auprès : du ministère de l’Éducation, du Loisir et du Sport; du Conseil supérieur de l’éducation, en siégeant aux comités proposant l’amélioration de la pédagogie et l’avancement de l’enseignement. Pour réaliser ses objectifs, l’Apec… fait des recommandations à tout organisme public et privé sur toute question concernant l’enseignement; organise des activités de perfectionnement pour ses membres par un séminaire annuel et des journées-rencontres; produit et diffuse des documents d’information en formation professionnelle; fait des études et des recherches en pédagogie de formation; facilite les contacts entre l’école et le milieu des affaires pour promouvoir une coopération dans la complémentarité; permet des échanges d’idées et la circulation d’information parmi ses membres par différents moyens technologiques; s’associe aux organismes faisant la promotion de la formation professionnelle.', 'https://www.profapec.com/', 'https://www.profapec.com/wp-content/uploads/2018/10/cropped-apec_full-2-5.png', 'Formation générale et diplômes'],
            ['APED', 'Assistance à la Personne en Établissement et à Domicile', 'Objectifs du programme Le programme d\'études professionnelles Assistance à la personne en établissement et à domicile prépare à l\'exercice de la profession de préposées et de préposés aux bénéficiaires et d\'aides familiales résidentes et d\'aides familiaux résidents dans le domaine de la santé et des services sociaux. Cette profession vise à offrir de l\'aide et des soins d\'assistance à une clientèle de tout âge présentant des maladies ou des incapacités physiques, psychiques ou psychosociales dans les réseaux public, privé et communautaire. La raison d\'être de la profession est de suppléer aux incapacités de la personne et de l\'assister dans le maintien ou le rétablissement de son autonomie et de son état de santé.', 'https://www.inforoutefpt.org/formation-professionnelle/diplome-etudes-professionnelles/5358', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Associations et organismes professionnels'],
            ['APEMIQ', 'Association Pour les Enseignants des Métiers Industriels du Québec', 'Mission L’APEMIQ a pour objet. De développer et de promouvoir la communication entre les enseignantes et les enseignants des secteurs de la mécanique industrielle. De représenter les intérêts de la formation, des enseignantes et des enseignants des secteurs de la mécanique industrielle. De suggérer au ministère, aux universités et aux entreprises des modifications et améliorations relatives au perfectionnement. De maintenir et de promouvoir les relations professionnelles entre les enseignantes et les enseignants et l’industrie. De suggérer au ministère du Québec des améliorations en regard des programmes d’enseignement des secteurs de la mécanique industrielle. De fournir de la documentation et d’autres renseignements d’ordre pédagogique et professionnel aux membres de l’Association. Voir les colloques annuels', 'https://apemiq.com/', 'https://secure.gravatar.com/blavatar/5e1f6f367180a58818853a22d283e6025c0cbd434296541bd9dbfb1957c09895?s=200&ts=1693225634', 'Associations et organismes professionnels'],
            ['APOP', 'Association pour les applications Pédagogiques de l\'Ordinateur au Postsecondaire', 'À PROPOS D’ÉDUCTIVE Éductive est la plateforme de Collecto destinée au personnel pédagogique du réseau collégial québécois. Par l’entremise du site , le personnel pédagogique peut accéder à de nombreuses ressources et activités offertes pour soutenir le développement professionnel, le partage de pratiques innovantes dans l’enseignement et l’apprentissage ainsi que la mutualisation de ressources éducatives. Éductive est également un tremplin vers d’autres services de Collecto en pédagogie numérique pour accompagner les acteurs et actrices du réseau dans la transformation et l’enrichissement de leurs pratiques pédagogiques avec le numérique. Référence: Lien vers le site Internet Portail APOP: Lien vers le site Internet', 'https://www.apop.qc.ca/fr/', 'https://media.licdn.com/dms/image/C560BAQH1wesZzqx18g/company-logo_200_200/0/1630564632972/apop_logo?e=2147483647&v=beta&t=hsyZNGWpJd-G-oF6aZTSoP40eorvTFDyGcM3xXTPEWI', 'Formation générale et diplômes'],
            ['AQAET', 'Association Québécoise de l\'Alternance Études-​Travail', 'Site: https://www.aqaet.qc.ca', 'https://www.aqaet.qc.ca', '', 'Associations et organismes professionnels'],
            ['AQEFLS', 'Association Québécoise pour l\'Enseignement du Français, Langue Seconde', 'Depuis 1978! L’Association québécoise pour l\'enseignement du français langue seconde (AQEFLS) est une association professionnelle gérée par des bénévoles qui ont à cœur le développement professionnel de ses membres et la valorisation de l\'enseignement du français langue seconde au Québec. L\'AQEFLS a été créée en 1978 et offre depuis lors des activités de formation continue de qualité ainsi que des opportunités de réseautage professionnel pour ses membres. Lien vers le site Internet', 'https://sites.google.com/view/aqefls/accueil?authuser=0', 'https://drive.google.com/thumbnail?id=1OGNlzYm3lSiPAjwU6KOtNRWZJOTe1qKv&sz=w1000', 'Associations et organismes professionnels'],
            ['AQEP', 'L’Association Québécoise des Enseignants.es du Primaire', 'L’AQEP c’est… l’Association Québécoise des Enseignant.es du Primaire. Elle regroupe toutes les personnes œuvrant, de près ou de loin, auprès de l’un des trois cycles de l’enseignement primaire afin de créer une communauté enseignante forte et dynamique.', 'https://www.aqep.org/fr/', 'https://cdn.ca.yapla.com/company/CPY9Mx8gybs7k5inzVetXhTJo/asset/images/Logos/Logo_Header.svg', 'Associations et organismes professionnels'],
            ['AQERS', 'Association Québécoise des Enseignants Responsables de Stages', '', '', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Associations et organismes professionnels'],
            ['AQETA', 'Association Québécoise des Troubles D\'apprentissage', '', 'https://sante.gouv.qc.ca/repertoire-ressources/ressource/?nofiche=872646&amp;ch_type=&amp;bt_rechType=&amp;theme=autres-ressources&amp;ch_choixReg=&amp;ch_rayon=0&amp;ch_code=&amp;page=99#info-generale', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Associations et organismes professionnels'],
            ['AQIFGA', 'Association Québécoise des Intervenant.e.s en Formation Générale des Adultes', '', '', 'https://aqifga.com/wp-content/uploads/2021/09/Logo_Hauteur_bleu_transparent200px.png', 'Associations et organismes professionnels'],
            ['AQPF', 'Association Québécoise des Professeur.e.s de Français', 'Association québécoise des professeur.e.s de français L’AQPF contribue à la qualité et à l’amélioration de l’enseignement du français par la réflexion, la formation continue, la diffusion de recherches et d’informations. Elle s’engage pédagogiquement, socialement et politiquement dans la défense et la promotion de la langue française et de son enseignement au Québec. Elle fait également la promotion de la culture québécoise et francophone.', 'https://aqpf.qc.ca/', 'https://aqpf.qc.ca/wp-content/uploads/2021/02/aqpf_logo_2020_aqpf_logo2020_rgb_centre.png', 'Formation générale et diplômes'],
            ['AQPS', 'Colloque de l’Association Québécoise des Professeurs de Santé', 'Lien vers le site: https://aqps.info', 'https://aqps.info', 'https://aqps.info/wp-content/uploads/2022/10/logo_principal.png', 'Associations et organismes professionnels'],
            ['AQUOPS', 'Association Québécoise des Utilisateurs d’Outils technologiques à des fins Pédagogiques et Sociales!', 'Colloque de l’AQUOPS à ne pas manquer chaque année. L’Association Québécoise des Utilisateurs d’Outils technologiques à des fins Pédagogiques et Sociales. Notre mission « Apprendre ensemble à l’ère du numérique! ». Nos valeurs : le partage, l’engagement et le dépassement. https://www.aquops.qc.ca/', 'https://www.aquops.qc.ca/', 'https://www.aquops.qc.ca/wp-content/themes/betheme/images/aquops_logo_homepage.png', 'Associations et organismes professionnels'],
            ['ASD', 'Assistance Soins Dentaire', 'Objectifs du programme Acquérir les connaissances, les habiletés et les attitudes nécessaires pour prendre les rendez-vous, accueillir la clientèle, préparer le matériel nécessaire et assister la ou le dentiste dans la prestation de traitements bucco-dentaires, donner les conseils postopératoires, exécuter des tâches liées à la prévention et à la planification des traitements, au contrôle de la contamination, à la gestion des déchets biomédicaux ainsi qu’à l’administration des affaires courantes, fabriquer des pièces et des modèles en laboratoire.', 'https://www.inforoutefpt.org/formation-professionnelle/diplome-etudes-professionnelles/5144', 'https://www.inforoutefpt.org/images/ogImageDefault.jpg', 'Gestion et administration scolaire'],
            ['ASP', 'Attestation de Spécialisation Professionnelle', '', '', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Formation professionnelle et technique'],
            ['ASPID', 'Adoption, Substitution, Progrès, Innovation, Détérioration', 'Définition Le modèle ASPID (Karsenti, 2018) est un schéma qui permet de catégoriser l\'utilité d\'une technologie dans l\'enseignement et l\'apprentissage. Il se compose de 5 pôle : Adoption, Substitution, Progrès, Innovation et Détérioration, ce qui lui donne son nom. Lorsqu\'une technologie est utilisée dans le cadre d\'un enseignement, elle se situe forcément à l\'un de ces pôles. Le modèle ASPID cherche à montrer que l\'usage d\'une technologie ne signifie pas forcément qu\'elle apporte une plus-value. Toutefois, si elle est bien mobilisée, elle permet d\'ouvrir un éventail de possibilités innovatives. Référence: Lien vers le site Internet Référence: L\'école branchée Référence: L’ intégration des TIC en contexte éducatif', 'https://edutechwiki.unige.ch/fr/Mod%C3%A8le_ASPID', 'https://recit.qc.ca/wp-content/uploads/2017/08/logo_recit.png', 'Technologies éducatives et numérique'],
            ['ATE', 'Alternance Travail-Études', 'On peut aussi dire ATÉ', '', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Formation professionnelle et technique'],
            ['ATE', 'Autres Tâches Éducatives', '', '', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Formation générale et diplômes'],
            ['ATEQ', 'Association Théâtre Éducation du Québec', 'Association des enseignants en art dramatique', 'https://theatreeducation.qc.ca/', 'https://theatreeducation.qc.ca/wp-content/uploads/2021/08/logo-entete-h150.png', 'Associations et organismes professionnels'],
            ['ATN', 'Académie de la Transformation Numérique', 'Notre mission: Une approche multidisciplinaire En positionnant les enjeux humains au cœur de sa démarche, l’Académie accompagne les organisations publiques et privées dans leur transformation numérique en matière d’acquisition de connaissances et de développement de compétences nécessaires à leurs employés et gestionnaires pour relever les défis que pose l’arrivée massive du numérique. Notre vision: L’humain avant tout Être reconnue de tous comme un leader dans le domaine de l’apprentissage numérique menant au développement d’une véritable culture numérique au Québec et ailleurs.', 'https://transformation-numerique.ulaval.ca/a-propos/', 'https://transformation-numerique.ulaval.ca/wp-content/themes/nubee/assets/images/logo-blanc.png', 'Technologies éducatives et numérique'],
            ['ATP', 'Autres tâches professionnelles', 'Les grandes nouveautés La tâche est désormais constituée de deux composantes la tâche éducative («TE»), composée des mêmes composantes qu’auparavant, dont les cours et leçons, et les autres tâches professionnelles («ATP»), composées des heures annuelles de ce qu\'on appelait auparavant la tâche complémentaire («TC»), les activités professionnelles («AP») ou les autres fonctions («AF»), selon les ententes locales, ainsi que du le travail personnel («TP»), qu’on appelait auparavant travail de nature personnelle («TNP»).', 'https://www.lafae.qc.ca/comprendre-la-tache-enseignante', 'https://lh3.googleusercontent.com/p/AF1QipPs9sl_bZ2e0gjbp6j9Ipsa11YX8MtN850IJsq5=s680-w680-h510', 'Formation générale et diplômes'],
            ['ATP', 'Assistance Technique en Pharmacie', 'Objectifs du programme Le programme d\'études Assistance technique en pharmacie prépare à l\'exercice du métier d\'assistante ou d\'assistant technique en pharmacie en établissement de santé et en pharmacie communautaire. L\'assistante ou l\'assistant technique en pharmacie (ATP) travaille sous la supervision d\'une pharmacienne ou d\'un pharmacien et l\'assiste pour l\'exécution des ordonnances, la constitution des dossiers-patients et l\'exécution des tâches techniques reliées à la préparation des médicaments.', 'https://www.inforoutefpt.org/formation-professionnelle/diplome-etudes-professionnelles/5341', 'https://www.inforoutefpt.org/images/ogImageDefault.jpg', 'Formation générale et diplômes'],
            ['AVS', 'Attestation of Vocational Spécialization', 'L\'AVS est l"équivalent anglais de l\'ASP Lien', 'https://www.inforoutefpt.org/vocational-training/attestation-of-vocational-specialization', 'https://www.inforoutefpt.org/images/ogImageDefault.jpg', 'Formation professionnelle et technique'],
            ['AÉPQ', 'Association d’Éducation Préscolaire du Québec', 'L’AÉPQ est une association québécoise qui regroupe plus de 2500 membres engagés et intéressés par l’éducation préscolaire.', 'https://www.aepq.ca/', 'https://aepq.ca/wp-content/uploads/2023/08/logo_70ans.svg', 'Associations et organismes professionnels'],
            ['BIM', 'Banque d’Instruments de Mesure', 'BIM La Banque d’instruments de mesure (BIM) est une banque d’épreuves qui facilite l\'évaluation des apprentissages. Notre équipe, composée de spécialistes en évaluation, d’agents de secrétariat, de graphistes et de réviseurs linguistiques, collabore avec des conseillers pédagogiques et des enseignants du réseau scolaire québécois, afin d\'offrir des épreuves de qualité.', 'https://bimenligne.qc.ca/fr', 'https://zoneapo.com/wp-content/uploads/2020/01/BIM_carre.png', 'Formation générale et diplômes'],
            ['BIQ', 'Bureau d\'Immigration du Québec', 'Immigration Arrima, apprendre le français, immigrer au Québec, faire un séjour d’études et obtenir de l’aide pour s’intégrer.', 'https://www.quebec.ca/immigration', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Ministères et organismes gouvernementaux'],
            ['BMOPAN', 'Bureau de la Mise en Oeuvre du Plan d’Action Numérique', 'Plan d\'action numérique en éducation et en enseignement supérieur Les élèves et les étudiants : au cœur de la révolution numérique', 'http://www.education.gouv.qc.ca/dossiers-thematiques/plan-daction-numerique/plan-daction-numerique/', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Technologies éducatives et numérique'],
            ['CABIIA', 'Communauté andragogique bilingue pour l’intégration de l’intelligence artificielle', 'Fondation de CABIIA : la Communauté andragogique bilingue pour l’intégration de l’intelligence artificielle Nous avons le plaisir d\'annoncer la création de CABIIA, une communauté de pratique dédiée à l\'intégration de l\'intelligence artificielle (IA) dans le domaine de l\'éducation des adultes et de la formation professionnelle au Québec. Mission : CABIIA vise à outiller les acteurs et actrices de l\'éducation des connaissances et compétences nécessaires afin de naviguer dans le paysage évolutif de l\'IA. Nous aborderons des sujets tels que les considérations éthiques, le fonctionnement de l\'IA, les outils pratiques, ainsi que les impacts sur les individus et la société. Objectifs : Bâtir une communauté soudée Croiser nos trajectoires et explorer ensemble S’enrichir et évoluer mutuellement', '', 'https://drive.google.com/thumbnail?id=1EPzCshI1NOX2qoEcdmHHwTFU8szZpjwc&sz=w1000', 'Associations et organismes professionnels'],
            ['CAG', 'Centre d\'Acquisitions Gouvernementales', 'Mission, vision et valeurs Notre mission Fournir aux ministères et organismes publics les biens et les services dont ils ont besoin dans l’exercice de leurs fonctions, et ce, dans l’objectif d’optimiser les acquisitions gouvernementales dans le respect des règles contractuelles applicables. Dans le cadre de ses activités, le CAG a comme préoccupation première de rencontrer les besoins en biens et services de l’ensemble des ministères et des organismes publics, incluant ceux du réseau de la santé et des services sociaux et des réseaux de l’éducation, à un juste prix, au bon moment et dans le respect de l’encadrement éthique, légal et financier. Il assure ainsi, à la population québécoise, l’accessibilité à des produits et à des services de qualité. Notre vision Être le chef de file en approvisionnement stratégique au gouvernement du Québec, axé sur ses clientèles et reconnu pour sa contribution à la société québécoise. Nos valeurs Le CAG entend s’appuyer sur des valeurs organisationnelles d\'intégrité, de sens du service à la clientèle, d\'innovation, de collaboration et d\'excellence qui seront partagées par tous et toutes au sein de l’organisation. Les cinq valeurs retenues, validées par l’ensemble des employés, servent de référence auprès du personnel. Lien Lien vers le site Internet', 'https://www.quebec.ca/gouvernement/ministeres-et-organismes/centre-dacquisitions-gouvernementales', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Ministères et organismes gouvernementaux'],
            ['CAP', 'Communauté d’Apprentissage Professionnelle', 'La communauté d’apprentissage professionnelle (CAP) favorise les transformations nécessaires pour la réussite éducative des élèves. Ce mode de fonctionnement développe l’intelligence collective de l’école en créant un espace de collaboration qui amène les acteurs scolaires à partager leurs réflexions quant aux apprentissages des élèves, et à se questionner sur les manières dont leurs pratiques puissent répondre davantage aux besoins de ces derniers. La CAP vise entre autres à implanter les stratégies reconnues à haut rendement afin de voir progresser tous les élèves. CAP - Professionnel https://cap.ctreq.qc.ca/', 'https://cap.ctreq.qc.ca/', 'https://www.ctreq.qc.ca/wp-content/uploads/2013/08/CTREQ-CAP-Logo.png', 'Formation générale et diplômes'],
            ['CAPFE', 'Comité d’Agrément des Programmes de Formation à l’Enseignement', 'À propos Créé en 1992, le Comité d\'agrément des programmes de formation à l\'enseignement (CAPFE) est devenu un organisme officiel en vertu de la Loi sur l\'instruction publique, sanctionnée le 19 décembre 1997. Le CAPFE est un comité autonome et indépendant relevant du ministre. Dans le cadre de sa mission, le Comité : examine et agrée les programmes de formation à l\'enseignement; recommande au ministre les programmes de formation à l\'enseignement aux fins de l\'obtention d\'une autorisation d\'enseigner; donne son avis au ministre sur la définition des compétences attendues des enseignants des ordres d\'enseignement primaire et secondaire.', 'https://www.quebec.ca/gouvernement/ministere/education/organismes-lies/comite-dagrement-des-programmes-de-formation-a-lenseignement-capfe', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Formation générale et diplômes'],
            ['CARRA', 'Commission Administrative des Régimes de Retraite et d’Assurances', '', '', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Ministères et organismes gouvernementaux'],
            ['CCCPFPT', 'Corporation des Conseillers pédagogiques en formation professionnelle et technique', 'La CCCPFPT est dissoute depuis l\'automne 2021. Il n\'y a donc plus aucune activité. Nous vous invitons à visiter le site de l\'ACCPQ pour vos besoins de ressources, d\'accompagnement ou de formation. https://accpq.org', 'https://accpq.org/?fbclid=IwAR3-JoOY2MFzpvpmqRLFLYJQ9RkkKsK9NrD_dAJjRmf7qNBMQ5xJGwKAjyg', 'https://i0.wp.com/accpq.org/wp-content/uploads/2020/08/cropped-ACCPQ_LOGO_arbre-et-lettre-sans-fond.png', 'Associations et organismes professionnels'],
            ['CCG', 'Comité Consultatif de Gestion', '', '', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Gestion et administration scolaire'],
            ['CCTT', 'Centres Collégiaux de Transfert de Technologies', 'NOTRE MISSION - NOTRE RAISON D\'ÊTRE Maximiser l’impact de l’expertise collective et individuelle des CCTT en innovation et en recherche appliquée dans le développement socio-économique du Québec et du Canada. À la fois par un transfert accru dans des milieux preneurs de procédés, de pratiques, de processus et de produits plus innovants, mais aussi par la contribution au développement d’une main-d’œuvre hautement qualifiée et innovante. Lien vers le site Internet', 'https://reseaucctt.ca/', 'https://www.ledevoir.com/documents/image/ReseauCCTT_logo-Synchronex_CMYK_Couleur-noir.png', 'Technologies éducatives et numérique'],
            ['CDL', 'Comité De Liaison du RÉCIT', '', '', 'https://recit.qc.ca/wp-content/uploads/2017/08/logo_recit.png', 'Technologies éducatives et numérique'],
            ['CDSI', 'Chef Délégué de la Sécurité de l’Information', 'DIRECTIVE GOUVERNEMENTALE SUR LA SÉCURITÉ DE L’INFORMATION', 'https://www.tresor.gouv.qc.ca/fileadmin/PDF/ressources_informationnelles/directives/directive_securite_information2021.pdf', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Ministères et organismes gouvernementaux'],
            ['CDÉACF', 'Centre de Documentation sur l’Éducation des Adultes et la Condition Féminine', '', '', 'https://cdeacf.ca/sites/all/themes/custom/cdeacf2013/CDEACF_logo-FB.png', 'Formation générale et diplômes'],
            ['CEA', 'Centre d\'Éducation des Adultes', '', '', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Formation générale et diplômes'],
            ['CEBM', 'Centre of Excellence for Behaviour Management', 'Lien vers le site Internet', 'https://www.cebm.ca/', 'https://static.wixstatic.com/media/afdd43_2df55334553d482fa3ef601009724371~mv2.png/v1/fill/w_136,h_96,al_c,q_85,usm_0.66_1.00_0.01,enc_auto/afdd43_2df55334553d482fa3ef601009724371~mv2.png', 'Technologies éducatives et numérique'],
            ['CEES', 'Certificat d\'Équivalence d\'Études Secondaires', 'La réussite du GED permet l’obtention du certificat d’équivalence d’études secondaires (CEES) Le CEES permet d’accéder à la formation professionnelle de niveau secondaire et à certains programmes de formation collégiale Le CEES est reconnu par plusieurs employeurs', 'https://qualificationsquebec.com/reconnaissance-competences/sarca/', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Formation professionnelle et technique'],
            ['CEHDAA', 'Comité consultatif d’Enseignantes et d’enseignants pour les élèves
Handicapés ou en Difficulté d’Adaptation ou d’Apprentissage', '', '', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Services aux élèves et adaptation'],
            ['CEMEQ', 'Centre d’Élaboration des Moyens d’Enseignement du Québec', 'Le CEMEQ est un organisme à but non lucratif qui développe du matériel pédagogique conçu pour la formation professionnelle en collaboration avec les centres de services scolaires du Québec. Lien vers le site: https://www.cemeq.qc.ca', 'https://www.cemeq.qc.ca', 'https://www.anel.qc.ca/wp-content/uploads/2018/08/CEMEQ_signature.jpg', 'Formation générale et diplômes'],
            ['CEMH', 'Centre of Excellence for Mental Health', 'Lien vers le site Internet', 'https://cemh.lbpsb.qc.ca/', 'https://cemh.lbpsb.qc.ca/portals/cemh/images/new.png', 'Technologies éducatives et numérique'],
            ['CEMIS', 'Centres d\'Enrichissement en Micro-Informatique Scolaire', 'Ancêtre du RÉCIT, les Centres d\'Enrichissement en Micro-Informatique Scolaire ont été créés en 1988.', '', 'https://recit.qc.ca/wp-content/uploads/2017/08/logo_recit.png', 'Technologies éducatives et numérique'],
            ['CERAC FP', 'Centre d\'Expertise en Reconnaissance des Acquis des Compétences en Formation Professionnelle', 'QU\'EST-CE QUE LA RAC La reconnaissance des acquis et des compétences (RAC) en formation professionnelle est une démarche qui permet de faire évaluer et reconnaître officiellement les compétences acquises grâce à des expériences de vie et de travail en fonction d’un programme d’études. La RAC se base sur trois principes : > Une personne a droit à la reconnaissance sociale de ses acquis et de ses compétences dès lors qu\'elle fournit la preuve qu\'elle les possède. > Une personne n\'a pas à réapprendre ce qu\'elle sait déjà ni à refaire dans un contexte scolaire formel, des apprentissages qu\'elle a déjà réalisés dans d\'autres lieux, selon d\'autres modalités. Ce qui importe en RAC, c\'est ce qu\'une personne a appris et non les lieux, les circonstances ou les méthodes d\'apprentissage. > Une personne doit être exemptée d\'avoir à faire reconnaître de nouveau des compétences ou des acquis qui ont été évalués avec rigueur et sanctionnés à l\'intérieur d\'un système officiel.', 'http://www.ceracfp.ca/', 'https://drive.google.com/thumbnail?id=1xyd_ftzT0bQdw-n9BljnB8bkM7A7TIbt&sz=w1000', 'Formation professionnelle et technique'],
            ['CFGA', 'Centre de Formation Générale des Adultes', '', '', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Formation générale et diplômes'],
            ['CFISA', 'Certificat de Formation en Insertion Socioprofessionnelle des Adultes', 'Intégration socioprofessionnelle Le service d’enseignement Intégration socioprofessionnelle a pour objectif d’offrir à l’adulte des moyens de développer son employabilité, d’intégrer le marché du travail et de faciliter son maintien à l’emploi. Ce service lui offre également la perspective de poursuivre des études. Le programme d’études associé à ce service s’inscrit dans une perspective de développement professionnel au cours duquel l’adulte est amené à prendre en charge ses apprentissages en vue de développer les compétences qui lui permettront de relever les défis liés aux nouvelles réalités du marché du travail. Il peut conduire à l’acquisition du certificat de formation en insertion socioprofessionnelle des adultes (CFISA) ou au certificat de formation à un métier semi-spécialisé (CFMS). Une passerelle donnant accès à la formation professionnelle demeure en vigueur.', 'http://www.education.gouv.qc.ca/adultes/formation-generale-des-adultes/integration-socioprofessionnelle/', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Formation professionnelle et technique'],
            ['CFMS', 'Certificat de Formation à un Métier Semi-spécialisé', 'Certificat de formation à un métier semi-spécialisé (CFMS) Sur recommandation du centre de services scolaire ( CSS ) ou de la commission scolaire anglophone ou à statut particulier ( CS ), un CFMS est décerné au jeune ou à l’adulte qui est inscrit à la Formation menant à l’exercice d’un métier semi-spécialisé de la formation générale des jeunes ou au programme d’études Intégration socioprofessionnelle de la formation générale des adultes et qui a : suivi la formation d’une durée minimale de 900 heures (qui comprend 450 heures de formation générale et 450 heures de formation pratique); réussi la formation pratique relative à ce métier semi-spécialisé d’une durée minimale de 450 heures.', 'http://www.education.gouv.qc.ca/gouvernance-scolaire/references/metiers-semi-specialises/certificats-de-formation/', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Centres de services scolaires'],
            ['CFPT', 'Certificat en Formation Préparatoire au Travail', 'Certificat de formation préparatoire au travail (CFPT) Sur recommandation du CSS ou de la CS , un CFPT est décerné au jeune qui est inscrit à la Formation préparatoire au travail de la formation générale des jeunes et qui a : suivi la formation d’une durée minimale de 2 700 heures; réussi la matière Insertion professionnelle, d’une durée minimale de 900 heures.', 'http://www.education.gouv.qc.ca/gouvernance-scolaire/references/metiers-semi-specialises/certificats-de-formation/', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Formation générale et diplômes'],
            ['CGRI', 'Comité de Gouvernance en Ressources Informationnelles', 'DIRECTIVE GOUVERNEMENTALE SUR LA SÉCURITÉ DE L’INFORMATION', 'https://www.tresor.gouv.qc.ca/fileadmin/PDF/ressources_informationnelles/directives/directive_securite_information2021.pdf', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Ministères et organismes gouvernementaux'],
            ['CGSI', 'Chef Gouvernemental de la Sécurité de l’Information', 'DIRECTIVE GOUVERNEMENTALE SUR LA SÉCURITÉ DE L’INFORMATION', 'https://www.tresor.gouv.qc.ca/fileadmin/PDF/ressources_informationnelles/directives/directive_securite_information2021.pdf', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Ministères et organismes gouvernementaux'],
            ['CIFIT', 'Centre Intégré de Formation et d\'Innovation Technologique', 'Centre intégré de formation et d’innovation technologique (CIFIT) Formation professionnelle, Secondaire Nous visons pour nos élèves le développement de compétences reconnues, recherchées et axées sur la pratique d’un métier passionnant. Nos centres à la fine pointe de la technologie regorgent de gens passionnés qui évoluent dans un environnement stimulant et branché sur le marché du travail.', 'https://www.cssbf.gouv.qc.ca/ecole/centre-integre-de-formation-et-dinnovation-technologique-cifit/', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Technologies éducatives et numérique'],
            ['CITNUM', 'Citoyenneté Numérique', '', 'https://www.citnum.ca', 'https://static.wixstatic.com/media/666e56_54175793f43c44828cebdd97291fc81b~mv2.png/v1/fill/w_112,h_122,al_c,q_85,usm_0.66_1.00_0.01,enc_auto/logo_citnum.png', 'Technologies éducatives et numérique'],
            ['CIUSSS', 'Centre Intégré Universitaire de Santé et de Services Sociaux', 'Centres intégrés de santé et de services sociaux (CISSS) et centres intégrés universitaires de santé et de services sociaux (CIUSSS) Les centres intégrés de santé et de services sociaux (CISSS) et les centres intégrés universitaires de santé et de services sociaux (CIUSSS) assurent l\'accessibilité, la continuité et la qualité des services destinés à la population de leur territoire. Ils constituent des points de référence où la population peut s\'adresser en cas de problèmes de santé et de problèmes psychosociaux. La population peut y recevoir les services appropriés ou être dirigée vers une autre ressource faisant partie du réseau territorial de services. D’autres établissements du réseau de la santé et des services sociaux (4 centres hospitaliers universitaires et 3 instituts universitaires) offrent des services spécialisés et surspécialisés et ce, au-delà de leur région sociosanitaire d’appartenance. Certains autres établissements publics desservent également une population nordique et autochtone.', 'https://www.quebec.ca/sante/systeme-et-services-de-sante/organisation-des-services/cisss-et-ciusss', 'https://www.msss.gouv.qc.ca/img/piv/MSSS_couleur.svg', 'Associations et organismes professionnels'],
            ['CJE', 'Carrefour Jeunesse-Emploi', 'Les Carrefours jeunesse-emploi (CJE) sont des organismes communautaires québécois sans but lucratif qui accompagnent et guident les jeunes adultes de 15 à 35 ans dans leurs démarches d’insertion sociale et économique, en aidant à leur cheminement vers l’emploi, vers un retour aux études ou dans le développement de projets.', 'https://fr.wikipedia.org/wiki/Carrefour_jeunesse-emploi', 'https://www.donneesquebec.ca/recherche/images/QUEBEC_couleur.svg', 'Associations et organismes professionnels'],
            ['CLC', 'Community Learning Centre', 'Lien vers le site Internet', 'https://clc.learnquebec.ca/', 'https://learnquebecweb.s3.ca-central-1.amazonaws.com/wp-content/uploads/sites/2/2022/02/21102243/logo-learn-blue-corporate.png', 'Technologies éducatives et numérique'],
            ['CLD', 'Centre Local de Développement', '', '', 'https://www.donneesquebec.ca/recherche/images/QUEBEC_couleur.svg', 'Gestion et administration scolaire'],
            ['CLE', 'Centre Local Emploi', '', '', 'https://www.donneesquebec.ca/recherche/images/QUEBEC_couleur.svg', 'Gestion et administration scolaire'],
            ['CLIFAD', 'Comité de Liaison Interordres en Formation À Distance', '', 'https://fadio.net/composition-des-comites/#:~:text=Le%20comit%C3%A9%20de%20liaison%20est,au%20sein%20de%20son%20organisation.', 'https://fadio.net/wp-content/uploads/2022/09/logo-fadio-h.png', 'Formation générale et diplômes'],
            ['CMS', 'content Management System', 'Système de gestion de contenu Un système de gestion de contenu1 ou SGC (content management system ou CMS en anglais) est un programme informatique permettant de créer un site internet, un blogue ou encore un site de vente en ligne. Les fonctionnalités d\'un SGC sont nombreuses. Il permet entre autres de travailler à plusieurs sur un même document ; de séparer les opérations de gestion de la forme et du contenu ; de structurer le contenu (FAQ, documents, blogues, forums, etc.) ; de hiérarchiser les utilisateurs et de leur attribuer des permissions (anonyme, administrateur, contributeur, etc.). Il fournit également une chaîne de publication (workflow) offrant par exemple la possibilité de mettre en ligne le contenu des documents. Certains SGC incluent la gestion des versions. Lorsque le SGC gère du contenu dynamique, on parle de système de gestion de contenu dynamique ou SGCD (Dynamic Content Management System ou DCMS). WordPress et Wix font partie des SGC. La notion de SGC ne doit pas être confondue avec les systèmes de gestion électronique des documents (GED) qui permettent de réaliser la gestion de contenu dans l\'entreprise (notamment le cycle de vie des documents).', 'https://fr.wikipedia.org/wiki/Syst%C3%A8me_de_gestion_de_contenu', 'https://recit.qc.ca/wp-content/uploads/2017/08/logo_recit.png', 'Technologies éducatives et numérique'],
            ['CNESST', 'Commission des Normes, de l’Équité, de la Santé et de la Sécurité
du Travail', 'La CNESST La Commission des normes, de l’équité, de la santé et de la sécurité du travail (CNESST) est l\'organisme auquel le gouvernement du Québec a confié la promotion des droits et des obligations en matière de travail. Elle en assure le respect auprès des travailleuses et travailleurs et des employeurs québécois.', 'https://www.cnesst.gouv.qc.ca/fr', 'https://www.cnesst.gouv.qc.ca/themes/custom/cnesst/assets/images/cnesst-logo-only.svg', 'Ministères et organismes gouvernementaux'],
            ['CNIPE', 'Carrefour National de l’Insertion Professionnelle en Enseignement', 'La présentation du CNIPE Réagissant au franc succès du premier colloque national de mai 2004 à Laval sur le thème de l’insertion professionnelle du personnel enseignant débutant, les partenaires souhaitaient poursuivre cette mission sur une base plus permanente donc répondre à l’invitation de « passer à l’action ». De réels besoins provenant du milieu scolaire de se préoccuper de l’entrée dans la profession et de proposer des modalités de soutien et d’accompagnement ont été relevés. Pour répondre à ces préoccupations, le Carrefour national de l’insertion professionnelle en enseignement (CNIPE) offre ses services, diffuse des informations pertinentes et soutient les efforts en insertion professionnelle grâce à l’appui tangible du ministère de l’Éducation (MEQ) et le soutien logistique du Centre de services scolaire de Laval. En 2009, un second colloque a réuni plus de 500 participants intéressés à poursuivre leurs réflexions et partager leurs bons coups en « donnant un nouvel élan à la profession enseignante ». Quelques séminaires et symposiums ont été proposés les années subséquentes rassemblant des gens de fonctions similaires pour amener plus loin le développement des dispositifs dans leur milieu selon leur sphère d’action et influencer, chacun à leur façon, la culture d’insertion professionnelle de leur milieu.', 'https://cnipe.ca/fr', 'https://cnipe.ca/medias/setting/main_logo_image/fr_logo.png.png', 'Associations et organismes professionnels'],
            ['CNPEPT', 'Comité National des Programmes d’Études Professionnelles et Techniques', 'Une approche adaptée pour la prospérité des régions Être qualifié pour un métier ou pour une profession est le meilleur moyen d’intégrer le marché du travail de façon durable. L’une des voies pour y parvenir est la formation professionnelle et technique. En effet, une grande partie des nombreux emplois qui seront disponibles au cours des prochaines années exigeront une telle formation. Et le Québec a la chance de compter sur des programmes d’excellente qualité. Cependant, certaines régions vivent une décroissance démographique et une baisse de leur effectif scolaire. Pour pouvoir compter sur des enseignants spécialisés en nombre suffisant, pour maintenir des installations, des laboratoires, des ateliers à la fine pointe de la technologie, pour faciliter le transfert technologique, pour offrir rapidement des programmes adaptés aux besoins émergents, les centres de formation professionnelle, les cégeps et les entreprises ont tout à gagner à unir leurs efforts. Voilà où l’intérêt d’un rapprochement prend tout son sens. Par ailleurs, les régions ont des réalités différentes, des assises économiques distinctes, des forces qui leur sont propres. Les acteurs régionaux doivent bénéficier de la latitude nécessaire afin de répondre avec efficacité à leurs besoins particuliers. C’est l’approche préconisée. Enfin, le passage de la formation professionnelle à la formation technique devrait se faire en continuité pour un diplômé qui voudrait poursuivre ses études. Plusieurs programmes devr', 'https://www.education.gouv.qc.ca/fileadmin/site_web/documents/dpse/educ_adulte_action_comm/PlanRapprochementFPT.pdf', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Technologies éducatives et numérique'],
            ['CO', 'Conseiller en Orientation', '', '', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Services aux élèves et adaptation'],
            ['COCD', 'Centre Opérationnel de CyberDéfense', 'Mission Créé en 2020, le Centre gouvernemental de cyberdéfense (CGCD) est un rouage essentiel de la protection des infrastructures numériques au Québec. Rattaché depuis 2022 au ministère de la Cybersécurité et du Numérique (MCN), le CGCD a pour mission de : Surveiller et contrer les risques et les menaces pouvant peser sur les organismes publics et les ministères; Prendre en charge les vulnérabilités détectées au niveau gouvernemental afin de prévenir les incidents; Déployer les mesures nécessaires afin de protéger les données gouvernementales. Parallèlement à sa mission de protection de la sécurité de l’information, le CGCD coordonne le Réseau gouvernemental de cyberdéfense, constitué de près d’une trentaine de centres opérationnels de cyberdéfense (COCD), ce qui lui permet de desservir l’ensemble des organismes publics en matière de cybersécurité. Plus spécifiquement, le CGCD est responsable : de mettre en place des pratiques sécuritaires dans l’utilisation, le développement et l’acquisition de solutions technologiques; de prendre en charge, de concert avec les divers intervenants, les incidents de sécurité de l’information ayant une portée gouvernementale; d’établir des liens avec des partenaires de confiance afin de constituer un réseau d’alerte performant dans l’identification et la prise en charge des cybermenaces; de soutenir et d’accompagner les organismes publics en cas de menace de cybersécurité ou d’incident dans le but d’atténuer les préjudices éventuels.', 'https://www.cyber.gouv.qc.ca/presentation/mission', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Technologies éducatives et numérique'],
            ['COEASD', 'Centre of Excellence for Autism Spectrum Disorder', 'Lien vers le site Internet', 'https://coeasd.lbpsb.qc.ca/', 'https://coeasd.lbpsb.qc.ca/Portals/asd/header-temp.png?ver=2021-05-11-145001-673', 'Technologies éducatives et numérique'],
            ['COEPIM', 'Centre of Excellence for the Phisically, Intellectually and Multi-Challenged', 'Lien vers le site Internet', 'https://coepim.ca/', 'https://coepim.ca/wp-content/uploads/2020/06/351x170.png', 'Technologies éducatives et numérique'],
            ['COESLD', 'Centre of Excellence for Speech and Language Development', 'Lien vers le site Internet', 'https://coesld.ca/', 'https://coesld.ca/wp-content/uploads/2022/07/Mask-Group-10.png', 'Technologies éducatives et numérique'],
            ['COSP', 'Contenus en Orientation Scolaire et Professionnelle', 'Orientation scolaire et professionnelle Les contenus en orientation scolaire et professionnelle (COSP) ont pour but d’outiller les élèves dans leur réflexion sur leurs choix professionnels. Ils les incitent à s’engager dans la préparation de leur avenir de la 5 e année du primaire jusqu’à la fin du secondaire. Les COSP favorisent ainsi la motivation et la persévérance scolaires. Ces contenus ont été déterminés en fonction des recommandations de membres du réseau scolaire et de spécialistes. Près de 230 écoles des réseaux public et privé les ont expérimentés dans le cadre d’un projet pilote.', 'http://www.education.gouv.qc.ca/enseignants/aide-et-soutien/services-educatifs-complementaires/orientation-scolaire-et-professionnelle/', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Associations et organismes professionnels'],
            ['COUD', 'Formations de courte durée', 'Site: https://www.cpmt.gouv.qc.ca/promoteurs-de-projets-de-formation/programmes-daide-financiere/formations-de-courte-duree-coud/', 'https://www.cpmt.gouv.qc.ca/promoteurs-de-projets-de-formation/programmes-daide-financiere/formations-de-courte-duree-coud/', 'https://joindre.education.gouv.qc.ca/commun/piv_ministeres/img/MEQ_couleur.svg', 'Formation professionnelle et technique'],
